const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

app.use(
  session({
    secret: process.env.SESSION_SECRET || 'change-this-session-secret',
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: false,
      sameSite: 'lax',
      maxAge: 10 * 60 * 1000
    }
  })
);

const twilioClient =
  process.env.TWILIO_ACCOUNT_SID &&
  process.env.TWILIO_AUTH_TOKEN
    ? twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN)
    : null;

const TWILIO_FROM = process.env.TWILIO_FROM_NUMBER || '';
const CODE_TTL_MS = 5 * 60 * 1000;
const MAX_ATTEMPTS = 5;

function generateSixDigitCode() {
  return crypto.randomInt(100000, 1000000).toString();
}

function normalizePhone(phone) {
  return String(phone || '').replace(/[^\d+]/g, '');
}

async function sendSms(to, body) {
  if (!twilioClient || !TWILIO_FROM) {
    console.log(`[DEV SMS] To: ${to} | Message: ${body}`);
    return { sid: 'dev-mode' };
  }

  return twilioClient.messages.create({
    body,
    from: TWILIO_FROM,
    to
  });
}

function ensureSession(req, res, next) {
  if (!req.session) {
    return res.status(500).json({ error: 'Session unavailable' });
  }
  next();
}

app.post('/2fa/send', ensureSession, async (req, res) => {
  try {
    const phone = normalizePhone(req.body.phone);

    if (!phone) {
      return res.status(400).json({ error: 'Phone number is required' });
    }

    const code = generateSixDigitCode();
    const expiresAt = Date.now() + CODE_TTL_MS;

    req.session.twoFactor = {
      phone,
      code,
      expiresAt,
      attempts: 0,
      verified: false
    };

    await sendSms(phone, `Your verification code is: ${code}`);

    return res.json({
      message: 'Verification code sent'
    });
  } catch (err) {
    return res.status(500).json({
      error: 'Failed to send verification code'
    });
  }
});

app.post('/2fa/verify', ensureSession, (req, res) => {
  const inputCode = String(req.body.code || '').trim();
  const record = req.session.twoFactor;

  if (!record) {
    return res.status(400).json({ error: 'No verification code requested' });
  }

  if (record.verified) {
    return res.json({ message: 'Already verified', verified: true });
  }

  if (Date.now() > record.expiresAt) {
    delete req.session.twoFactor;
    return res.status(400).json({ error: 'Verification code expired' });
  }

  if (!/^\d{6}$/.test(inputCode)) {
    return res.status(400).json({ error: 'Invalid code format' });
  }

  record.attempts += 1;

  if (record.attempts > MAX_ATTEMPTS) {
    delete req.session.twoFactor;
    return res.status(429).json({ error: 'Too many failed attempts' });
  }

  if (inputCode !== record.code) {
    return res.status(401).json({
      error: 'Incorrect verification code',
      attemptsRemaining: Math.max(0, MAX_ATTEMPTS - record.attempts)
    });
  }

  record.verified = true;
  record.verifiedAt = Date.now();
  delete record.code;

  return res.json({
    message: 'Two-factor authentication verified',
    verified: true
  });
});

app.get('/2fa/status', ensureSession, (req, res) => {
  const record = req.session.twoFactor;

  if (!record) {
    return res.json({
      requested: false,
      verified: false
    });
  }

  return res.json({
    requested: true,
    verified: !!record.verified,
    phone: record.phone,
    expiresAt: record.expiresAt
  });
});

app.post('/login', ensureSession, async (req, res) => {
  const { username, password, phone } = req.body;

  if (!username || !password || !phone) {
    return res.status(400).json({ error: 'username, password, and phone are required' });
  }

  const primaryAuthPassed = true;

  if (!primaryAuthPassed) {
    return res.status(401).json({ error: 'Invalid username or password' });
  }

  const normalizedPhone = normalizePhone(phone);
  const code = generateSixDigitCode();
  const expiresAt = Date.now() + CODE_TTL_MS;

  req.session.user = { username };
  req.session.twoFactor = {
    phone: normalizedPhone,
    code,
    expiresAt,
    attempts: 0,
    verified: false
  };

  try {
    await sendSms(normalizedPhone, `Your verification code is: ${code}`);
    return res.json({
      message: 'Primary authentication successful. 2FA code sent.',
      requiresTwoFactor: true
    });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to send 2FA code' });
  }
});

app.post('/login/complete', ensureSession, (req, res) => {
  const record = req.session.twoFactor;
  const user = req.session.user;

  if (!user) {
    return res.status(401).json({ error: 'No authenticated user session' });
  }

  if (!record || !record.verified) {
    return res.status(401).json({ error: 'Two-factor authentication not completed' });
  }

  req.session.isAuthenticated = true;

  return res.json({
    message: 'Login complete',
    authenticated: true,
    user
  });
});

app.post('/logout', ensureSession, (req, res) => {
  req.session.destroy(() => {
    res.json({ message: 'Logged out' });
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`2FA app listening on port ${PORT}`);
});